=IF(OR(Quoting!$C$4="", Quoting!$C$6="", Quoting!$C$9="", Quoting!$I$15="", Quoting!$I$16="", Quoting!$I$18="", Quoting!$I$19="", Quoting!$I$23=""), "",
ROUNDUP(
   IF(Quoting!$I$19=0,0,
      (
         IF(Quoting!$I$18="Parallel to Top",
            IF(Quoting!$I$15="Horizontal",
               Quoting!$C$6*12 - MAX(VALUE(LEFT(Quoting!$C$9,FIND("x",Quoting!$C$9)-1)), VALUE(MID(Quoting!$C$9,FIND("x",Quoting!$C$9)+1,10))) - Quoting!$I$21 - Quoting!$I$22,
               Quoting!$C$6*12 - MIN(VALUE(LEFT(Quoting!$C$9,FIND("x",Quoting!$C$9)-1)), VALUE(MID(Quoting!$C$9,FIND("x",Quoting!$C$9)+1,10))) - Quoting!$I$21 - Quoting!$I$22
            ),
            IF(Quoting!$I$18="Parallel to Height",
               IF(Quoting!$I$15="Horizontal",
                  Quoting!$C$4*12 - 2*MAX(VALUE(LEFT(Quoting!$C$9,FIND("x",Quoting!$C$9)-1)), VALUE(MID(Quoting!$C$9,FIND("x",Quoting!$C$9)+1,10))),
                  Quoting!$C$4*12 - 2*MIN(VALUE(LEFT(Quoting!$C$9,FIND("x",Quoting!$C$9)-1)), VALUE(MID(Quoting!$C$9,FIND("x",Quoting!$C$9)+1,10)))
               )
            )
         )
         * (Quoting!$I$23/100)
      )
      / IF(Quoting!$I$15="Horizontal",
         MAX(VALUE(LEFT(Quoting!$I$16,FIND("x",Quoting!$I$16)-1)), VALUE(MID(Quoting!$I$16,FIND("x",Quoting!$I$16)+1,10))),
         MIN(VALUE(LEFT(Quoting!$I$16,FIND("x",Quoting!$I$16)-1)), VALUE(MID(Quoting!$I$16,FIND("x",Quoting!$I$16)+1,10)))
      )
   ),0)
)

